"""Dual-indexed registry: items accessible by both integer ID and string name.

Invariant: _by_id, _by_name, and _count must always be consistent.
  - len(_by_id) == len(_by_name) == _count
  - For every (id, item) in _by_id, _by_name[item.name] is the same item.
"""
from dataclasses import dataclass, field
from typing import Dict, Optional, Any


@dataclass
class Item:
    """A registry item with an ID, name, and arbitrary data."""
    id: int
    name: str
    data: Any = None


class Registry:
    """Maintains items indexed by both ID and name.

    Both indexes must always agree: every item in _by_id must also
    appear in _by_name under its current name, and vice versa.
    """

    def __init__(self):
        self._by_id: Dict[int, Item] = {}
        self._by_name: Dict[str, Item] = {}
        self._count: int = 0
        self._next_id: int = 1

    def add(self, name: str, data: Any = None) -> Item:
        """Add an item. Raises ValueError if name already exists."""
        if name in self._by_name:
            raise ValueError(f"Name '{name}' already exists")
        item = Item(id=self._next_id, name=name, data=data)
        self._by_id[item.id] = item
        self._by_name[name] = item
        self._count += 1
        self._next_id += 1
        return item

    def remove_by_id(self, item_id: int) -> Optional[Item]:
        """Remove an item by its ID. Returns the item or None."""
        item = self._by_id.pop(item_id, None)
        if item is None:
            return None
        del self._by_name[item.name]
        self._count -= 1
        return item

    def remove_by_name(self, name: str) -> Optional[Item]:
        """Remove an item by its name. Returns the item or None."""
        item = self._by_name.pop(name, None)
        if item is None:
            return None
        self._count -= 1
        return item

    def rename(self, old_name: str, new_name: str) -> Optional[Item]:
        """Rename an item. Raises ValueError if new_name is taken."""
        if new_name in self._by_name:
            raise ValueError(f"Name '{new_name}' already exists")
        item = self._by_name.pop(old_name, None)
        if item is None:
            return None
        item.name = new_name
        self._by_name[new_name] = item
        return item

    def get_by_id(self, item_id: int) -> Optional[Item]:
        """Look up by ID."""
        return self._by_id.get(item_id)

    def get_by_name(self, name: str) -> Optional[Item]:
        """Look up by name."""
        return self._by_name.get(name)

    def count(self) -> int:
        """Return the tracked item count."""
        return self._count

    def list_all(self) -> list:
        """Return all items (from the name index)."""
        return list(self._by_name.values())

