"""Cache layer over Registry for recent lookups.

Cache keys use the format "id:{id}" or "name:{name}".
When the registry mutates, affected cache entries must be invalidated.
"""
from typing import Optional, Any
from store import Registry, Item


class CacheLayer:
    """Caching proxy for Registry lookups.

    Wraps a Registry and caches get_by_id / get_by_name results.
    Mutations (add, remove, rename) invalidate relevant cache entries.
    """

    def __init__(self, registry: Registry):
        self._registry = registry
        self._cache: dict = {}

    def get_by_id(self, item_id: int) -> Optional[Item]:
        """Cached lookup by ID."""
        key = f"id:{item_id}"
        if key in self._cache:
            return self._cache[key]
        item = self._registry.get_by_id(item_id)
        if item is not None:
            self._cache[key] = item
        return item

    def get_by_name(self, name: str) -> Optional[Item]:
        """Cached lookup by name."""
        key = f"name:{name}"
        if key in self._cache:
            return self._cache[key]
        item = self._registry.get_by_name(name)
        if item is not None:
            self._cache[key] = item
        return item

    def add(self, name: str, data: Any = None) -> Item:
        """Add via registry and invalidate cache."""
        item = self._registry.add(name, data)
        return item

    def remove_by_id(self, item_id: int) -> Optional[Item]:
        """Remove by ID and invalidate cache."""
        item = self._registry.remove_by_id(item_id)
        if item is not None:
            self._cache.pop(f"id:{item_id}", None)
            self._cache.pop(f"name:{item.name}", None)
        return item

    def remove_by_name(self, name: str) -> Optional[Item]:
        """Remove by name and invalidate cache."""
        item = self._registry.remove_by_name(name)
        if item is not None:
            self._cache.pop(f"name:{name}", None)
            self._cache.pop(f"id:{item.id}", None)
        return item

    def rename(self, old_name: str, new_name: str) -> Optional[Item]:
        """Rename and invalidate cache entries."""
        item = self._registry.rename(old_name, new_name)
        if item is not None:
            self._cache.pop(f"name:{new_name}", None)
            self._cache.pop(f"id:{item.id}", None)
        return item

    def count(self) -> int:
        """Delegate to registry."""
        return self._registry.count()

    def list_all(self) -> list:
        """Delegate to registry."""
        return self._registry.list_all()

seed_files.api.py:
"""API layer wrapping Registry and CacheLayer.

Provides a simplified interface for external callers. Tracks its own
item count as an optimization shortcut.
"""
from typing import Optional, Any, Union
from store import Registry, Item
from cache import CacheLayer


class RegistryAPI:
    """High-level API for the item registry.

    Wraps CacheLayer (which wraps Registry) and provides convenience methods.
    Maintains its own _item_count as a fast-path optimization.
    """

    def __init__(self):
        self._registry = Registry()
        self._cache = CacheLayer(self._registry)
        self._item_count: int = 0

    def add_item(self, name: str, data: Any = None) -> int:
        """Add an item and return its ID."""
        item = self._cache.add(name, data)
        self._item_count += 1
        return item.id

    def move_item(self, item_id: int, new_name: str) -> bool:
        """Rename an item by its ID. Returns True on success."""
        item = self._registry.get_by_id(item_id)
        if item is None:
            return False
        old_name = item.name
        try:
            self._cache.rename(old_name, new_name)
            return True
        except ValueError:
            return False

    def remove_item(self, identifier: Union[int, str]) -> bool:
        """Remove an item by ID (int) or name (str)."""
        if isinstance(identifier, int):
            item = self._cache.remove_by_id(identifier)
            if item is not None:
                self._item_count -= 1
                return True
            return False
        else:
            item = self._cache.remove_by_name(identifier)
            if item is not None:
                return True
            return False

    def search(self, query: str) -> Optional[Item]:
        """Search for an item by name (exact match first, then scan)."""
        item = self._cache.get_by_name(query)
        if item is not None:
            return item
        for item in self._registry.list_all():
            if query.lower() in item.name.lower():
                return item
        return None

    def get_item(self, item_id: int) -> Optional[Item]:
        """Get an item by ID."""
        return self._cache.get_by_id(item_id)

    def item_count(self) -> int:
        """Return the API-tracked item count."""
        return self._item_count

    def registry_count(self) -> int:
        """Return the registry-tracked item count (for verification)."""
        return self._cache.count()

